export interface AuthBody {
  nick: string;
  password: string;
}

export interface AuthResponse {
  user: {
    id: number;
    nick: string;
  };
  accessToken: string;
  humans: Human[];
}

export interface Human {
  id: number;
  posX: number;
  posY: number;
  userId: number;
}

export enum AuthError {
  userAlreadyTaken = 'User already taken',
  invalidCredentials = 'Invalid credentials',
}
