import { Component, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormBuilder, FormsModule, ReactiveFormsModule, Validators } from '@angular/forms';
import { Router, RouterLink } from '@angular/router';
import { AuthService } from '../../services/api/auth';
import { ButtonComponent } from '../../components/dump/button/button';
import { HeaderComponent } from '../../components/dump/header/header';
import { InputComponent } from '../../components/dump/input/input';
import { passwordMatchValidator } from '../../validators/password';
import { HttpErrorResponse } from '@angular/common/http';
import { AuthError } from '../../services/api/api.models';

@Component({
  selector: 'home-page',
  imports: [CommonModule, RouterLink, FormsModule, ReactiveFormsModule, ButtonComponent, HeaderComponent, InputComponent],
  standalone: true,
  templateUrl: './home.html',
})
export class HomePage {
  private readonly authService = inject(AuthService);
  private readonly router = inject(Router);
  protected readonly formBuilder = inject(FormBuilder);

  protected readonly isLoginMode = signal(true);
  protected readonly loginError = signal<string | null>(null);
  protected readonly loading = signal<boolean>(false);

  protected readonly authForm = this.formBuilder.nonNullable.group({
    nick: ['', [Validators.required]],
    password: ['', [Validators.required]],
    confirmPassword: ['', []],
  });

  protected toggleRegister() {
    this.authForm.reset();
    this.isLoginMode.set(!this.isLoginMode());
    if (this.isLoginMode()) {
      this.authForm.controls.nick.setValidators([Validators.required]);
      this.authForm.controls.password.setValidators([Validators.required]);
      this.authForm.controls.confirmPassword.setValidators([]);
      this.authForm.removeValidators(passwordMatchValidator);
    } else {
      this.authForm.controls.nick.setValidators([Validators.required, Validators.minLength(3)]);
      this.authForm.controls.password.setValidators([Validators.required, Validators.minLength(8)]);
      this.authForm.controls.confirmPassword.setValidators([Validators.required]);
      this.authForm.addValidators(passwordMatchValidator);
    }
  }

  protected async submit() {
    if (this.loading()) {
      return;
    }
    this.loading.set(true);
    this.loginError.set(null);
    this.authForm.markAllAsTouched();

    if (this.authForm.valid) {
      try {
        const { nick, password } = this.authForm.value;
        if (!nick || !password) {
          return;
        }
        if (this.isLoginMode()) {
          await this.authService.login(nick, password);
        } else {
          await this.authService.register(nick, password);
        }
        await this.router.navigate(['/game']);
      } catch (error: any) {
        switch (error?.error?.message) {
          case AuthError.invalidCredentials:
            this.loginError.set('Błędny login lub hasło');
            break;
          case AuthError.userAlreadyTaken:
            this.loginError.set('Ten nick jest już zajęty');
            break;
          default:
            this.loginError.set('Błąd serwera');
        }
      }
    }
    this.loading.set(false);
  }
}
